def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + 30 * np.log1p(cap)
        fluctuation = 0.0
        exponential_factor = np.exp(-usage)
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3) - 120 * np.sqrt(cap)
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * i * 1.1) * 50 / (i + 1)
            if cap > 15:
                base_priority += np.power(cap, 0.4) * 75 + 55 * np.sin(cap * 2.3)
            elif cap > 7:
                base_priority -= 85 * np.tanh(usage - 4.5)
            else:
                base_priority -= 72 * usage
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2 + 320 * (1 - delta)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * j ** 1.1) * 35 / j
            if int(cap * 4.7) % 5 == 1:
                base_priority += 45 * np.sin(cap / 17)
        elif 3 < usage <= 4:
            base_priority += 1600 * (usage - 3) ** 1.7 + 230 * (1 - (usage - 3) ** 0.5)
            for k in range(1, 13):
                val = usage ** k
                if val < 0.35:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 10 and usage > 3.6:
                        fluctuation += 25
            if cap % 2.7 < 0.6:
                base_priority += 38 * np.cos(cap * 3.3)
        elif 2 < usage <= 3:
            base_priority += 1300 * (usage - 2) ** 2.3
            for m in range(1, 17):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 22 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 16 / (m + 4)
                    if m == 14 and usage > 2.7:
                        fluctuation += 30
            if cap % 3.1 < 0.4:
                base_priority += 50 * np.sin(cap * 4)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1) ** 3.5
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.55:
                    fluctuation += pwr * 30 / n
                    if n % 4 == 3:
                        fluctuation -= 5 * n
                else:
                    fluctuation += (1 - pwr) * 15 / (n + 2)
                    if n == 18 and usage > 1.8:
                        fluctuation += 40
            if cap % 1.8 < 0.35:
                base_priority += 33 * np.cos(cap * 2.5)
        elif 0.3 < usage <= 1:
            base_priority += 140 * (1 - usage) + 80 * np.exp(-usage)
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.05 * o:
                    fluctuation -= 10 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 310
            elif cap < 0.8:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 6) * 25
        else:
            base_priority += 300 * (1 - usage) ** 2.5
            for p in range(1, 21):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 15 / p
                if usage < 0.012 * p:
                    fluctuation -= 15 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 340
            elif cap < 1.0:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation + exponential_factor * 100
        if cap < 0.03:
            priority += 80
            if usage > 0.7:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for q in range(1, 9):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 0.7:
            priority += 45
            if usage > 0.8:
                priority += 70
            elif usage < 0.15:
                priority -= 35
            for r in range(1, 8):
                if int(cap * 1500) % (r + 5) in [0,2]:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 50
                for s in range(1, 9):
                    priority -= s * 6
            elif usage > 0.9:
                priority += 100
                for t in range(1, 7):
                    priority += t * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 18
        if int(cap * 1000) % 29 == 0:
            proximity -= 14
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.025:
                proximity += 24 / u
            elif diff < 0.06:
                proximity += 12 / u
            else:
                proximity -= 5 / u
        for v in range(1, 10):
            mod_chk = int(cap * 1800) % (v + 11)
            if mod_chk in [0,4]:
                proximity += v * 6
            elif mod_chk == 5:
                proximity -= v * 5
        for w in range(1, 6):
            mod_chk = int(usage * 1800) % (w + 8)
            if mod_chk in [0,2]:
                proximity += 12 * w
            elif mod_chk == 4:
                proximity -= 8 * w
        priority += proximity
        if usage < 0.004:
            for x in range(1, 10):
                priority -= x * 12
        elif usage > 0.9:
            for y in range(1, 9):
                priority += y * 14
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 3000) % 29 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 8):
                if (int(cap * 700) % (z + 11) == 3) and (usage < 0.8):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
